    line-height: 1.75;
    -webkit-font-smoothing: antialiased;
  }
  .container { max-width: 740px; margin: 0 auto; padding: 0 24px; }
  .hero {
    background: linear-gradient(135deg, #0d1929 0%, #0f1117 60%, #0a1a14 100%);
