    padding: 72px 0 56px;
  }
  .day-badge {
    display: inline-block;
    background: var(--tag);
    color: #fff;
    font-family: 'Courier New', monospace;
    font-size: 12px;
    font-weight: 700;
    letter-spacing: 2px;
    padding: 4px 12px;
    border-radius: 3px;
    text-transform: uppercase;
    margin-bottom: 20px;
  }
