    font-size: 2.4rem;
    line-height: 1.25;
    font-weight: 700;
    color: #f0f4ff;
    margin-bottom: 18px;
    letter-spacing: -0.5px;
  }
  .hero .subtitle {
    font-size: 1.05rem;
    color: var(--muted);
    font-style: italic;
    margin-bottom: 28px;
  }
  .hero-meta {
    display: flex;
    gap: 24px;
    flex-wrap: wrap;
    font-family: 'Courier New', monospace;
    font-size: 13px;
