    border-top: 1px solid var(--border);
    padding-top: 20px;
    margin-top: 28px;
  }
  .hero-meta span { display: flex; align-items: center; gap: 6px; }
  .hero-meta .dot { color: var(--accent); }
  .article { padding: 56px 0; }
  .article p { margin-bottom: 1.4em; }
  .article h2 {
    font-size: 1.55rem;
    font-weight: 700;
    color: #e8ecf8;
    margin: 56px 0 18px;
    padding-top: 8px;
    border-top: 2px solid var(--border);
    letter-spacing: -0.3px;
  }
  .article h2:first-child { margin-top: 0; border-top: none; }
  .article h3 {
    font-size: 1.15rem;
    font-weight: 700;
