  .callout .callout-label {
    font-family: 'Courier New', monospace;
    font-size: 12px;
    font-weight: 700;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    margin-bottom: 8px;
  }
  .callout.warn .callout-label { color: var(--warn); }
  .callout.danger .callout-label { color: var(--danger); }
  .callout.success .callout-label { color: var(--success); }
  .callout p { margin-bottom: 0; font-size: 0.95rem; }
  pre, code { font-family: 'Courier New', Courier, monospace; font-size: 0.85rem; }
